svg.script:
(function () {
	function initScan(retryCount) {
		var root = document.documentElement;
		var statusNode = root.getElementById('scan-status');
		var regionNode = root.getElementById('scan-region');
		var regionLabelLayer = root.getElementById('region-labels');
		var list = Array.prototype.slice.call(root.querySelectorAll('#Kecamatan > path')).filter(function (node) {
			var fill = (node.getAttribute('fill') || '').toLowerCase();
			return fill !== 'none';
		});

		if (!list.length) {
			if (retryCount < 12) {
				setTimeout(function () {
					initScan(retryCount + 1);
				}, 120);
				return;
			}

			if (statusNode) {
				statusNode.textContent = 'Mode scan: tidak tersedia';
			}
			return;
		}

		var index = 0;
		var timer = null;
		var pausedByUser = false;
		var landmarkIconLayer = root.getElementById('landmark-icons');
		var regionDistrictMap = {
			1: 'BALONGBENDO',
			2: 'BUDURAN',
			3: 'CANDI',
			4: 'GEDANGAN',
			5: 'JABON',
			6: 'KREMBUNG',
			7: 'KRIAN',
			8: 'PORONG',
			9: 'PRAMBON',
			10: 'SEDATI',
			11: 'SIDOARJO',
			12: 'SUKODONO',
			13: 'TAMAN',
			14: 'TANGGULANGIN',
			15: 'TARIK',
			16: 'TULANGAN',
			17: 'WARU',
			18: 'WONOAYU'
		};
		var regionLabelOffsets = {
			1: { x: 0, y: 0 },
			2: { x: 0, y: -20 },
			3: { x: 0, y: 0 },
			4: { x: 0, y: 0 },
			5: { x: 0, y: 23 },
			6: { x: 0, y: 0 },
			7: { x: 0, y: 0 },
			8: { x: 0, y: 0 },
			9: { x: 0, y: 0 },
			10: { x: 0, y: 0 },
			11: { x: 0, y: 0 },
			12: { x: 0, y: 0 },
			13: { x: 0, y: 0 },
			14: { x: 0, y: 0 },
			15: { x: 0, y: 0 },
			16: { x: 0, y: 0 },
			17: { x: 0, y: 0 },
			18: { x: 0, y: 0 }
		};
		var landmarkIconConfig = {
			1: { width: 55, height: 55, offsetX: 0, offsetY: -30 },
			2: { width: 55, height: 55, offsetX: 0, offsetY: -55 },
			4: { width: 55, height: 55, offsetX: 0, offsetY: -35 },
			5: { width: 55, height: 55, offsetX: 155, offsetY: 0 },
			6: { width: 55, height: 55, offsetX: -35, offsetY: -35 },
			9: { width: 55, height: 55, offsetX: 0, offsetY: -30 },
			11: { width: 100, height: 100, offsetX: 80, offsetY: 0 },
			13: { width: 55, height: 55, offsetX: -75, offsetY: 20 },
			14: { width: 55, height: 55, offsetX: 95, offsetY: 0 }
		};

		function ensureLabelLayerOnTop() {
			if (!regionLabelLayer) {
				regionLabelLayer = document.createElementNS('http://www.w3.org/2000/svg', 'g');
				regionLabelLayer.setAttribute('id', 'region-labels');
			}

			if (regionLabelLayer.parentNode !== root) {
				root.appendChild(regionLabelLayer);
			}

			if (root.lastChild !== regionLabelLayer) {
				root.appendChild(regionLabelLayer);
			}
		}

		function ensureLandmarkLayerOnTop() {
			if (!landmarkIconLayer) {
				landmarkIconLayer = document.createElementNS('http://www.w3.org/2000/svg', 'g');
				landmarkIconLayer.setAttribute('id', 'landmark-icons');
				landmarkIconLayer.setAttribute('pointer-events', 'none');
			}

			if (landmarkIconLayer.parentNode !== root) {
				root.appendChild(landmarkIconLayer);
			}

			if (root.lastChild !== landmarkIconLayer) {
				root.appendChild(landmarkIconLayer);
			}
		}

		function getRegionName(position, node) {
			var custom = node.getAttribute('data-region-name');
			if (custom) {
				return custom;
			}

			var districtName = regionDistrictMap[position + 1];
			if (districtName) {
				return districtName;
			}

			return 'Region ' + (position + 1);
		}

		function getRegionAnchor(region, bbox) {
			var baseCenterX = bbox.x + bbox.width / 2;
			var baseCenterY = bbox.y + bbox.height / 2;

			if (!region || typeof region.isPointInFill !== 'function' || typeof root.createSVGPoint !== 'function') {
				return { x: baseCenterX, y: baseCenterY };
			}

			var point = root.createSVGPoint();
			var samplesX = 10;
			var samplesY = 10;
			var bestX = baseCenterX;
			var bestY = baseCenterY;
			var bestDistance = Number.POSITIVE_INFINITY;
			var foundInsidePoint = false;

			for (var ix = 0; ix <= samplesX; ix += 1) {
				for (var iy = 0; iy <= samplesY; iy += 1) {
					var x = bbox.x + (bbox.width * ix) / samplesX;
					var y = bbox.y + (bbox.height * iy) / samplesY;

					point.x = x;
					point.y = y;

					if (!region.isPointInFill(point)) {
						continue;
					}

					foundInsidePoint = true;
					var dx = x - baseCenterX;
					var dy = y - baseCenterY;
					var distance = dx * dx + dy * dy;

					if (distance < bestDistance) {
						bestDistance = distance;
						bestX = x;
						bestY = y;
					}
				}
			}

			if (!foundInsidePoint) {
				return { x: baseCenterX, y: baseCenterY };
			}

			return { x: bestX, y: bestY };
		}

		function renderRegionLabels() {
			if (!regionLabelLayer) {
				return;
			}

			ensureLabelLayerOnTop();

			while (regionLabelLayer.firstChild) {
				regionLabelLayer.removeChild(regionLabelLayer.firstChild);
			}

			for (var i = 0; i < list.length; i += 1) {
				var region = list[i];
				var regionNumber = i + 1;
				var regionLabel = getRegionName(i, region);

				try {
					var bbox = region.getBBox();
					if (!bbox || bbox.width <= 0 || bbox.height <= 0) {
						continue;
					}

					var anchorPoint = getRegionAnchor(region, bbox);
					var offset = regionLabelOffsets[regionNumber] || { x: 0, y: 0 };
					var centerX = anchorPoint.x + offset.x;
					var centerY = anchorPoint.y + offset.y;
					var labelWidth = Math.max(52, Math.min(176, Math.round(regionLabel.length * 6.45 + 20)));
					var labelHeight = 17;

					var labelGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g');
					var labelRect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
					var labelText = document.createElementNS('http://www.w3.org/2000/svg', 'text');

					labelRect.setAttribute('x', String(centerX - labelWidth / 2));
					labelRect.setAttribute('y', String(centerY - labelHeight / 2));
					labelRect.setAttribute('width', String(labelWidth));
					labelRect.setAttribute('height', String(labelHeight));
					labelRect.setAttribute('rx', '5');
					labelRect.setAttribute('class', 'region-label-bg');

					labelText.setAttribute('x', String(centerX));
					labelText.setAttribute('y', String(centerY + 0.5));
					labelText.setAttribute('class', 'region-label-text');
					labelText.textContent = regionLabel;

					labelGroup.appendChild(labelRect);
					labelGroup.appendChild(labelText);
					regionLabelLayer.appendChild(labelGroup);
				} catch (error) {
					continue;
				}
			}
		}

		function renderLandmarkIcons() {
				if (!landmarkIconLayer) {
					return;
				}

				ensureLandmarkLayerOnTop();

				var landmarkImages = Array.prototype.slice.call(landmarkIconLayer.querySelectorAll('image'));

				for (var i = 0; i < landmarkImages.length; i += 1) {
					var imageNode = landmarkImages[i];
					var regionNumber = Number(imageNode.getAttribute('data-region-index'));
					var region = list[regionNumber - 1];
					var iconConfig = landmarkIconConfig[regionNumber] || { width: 32, height: 32, offsetX: 0, offsetY: 0 };

					if (!region || typeof region.getBBox !== 'function') {
						continue;
					}

					try {
						var bbox = region.getBBox();
						if (!bbox || bbox.width <= 0 || bbox.height <= 0) {
							continue;
						}

						var width = Number(iconConfig.width) || Number(imageNode.getAttribute('width')) || 32;
						var height = Number(iconConfig.height) || Number(imageNode.getAttribute('height')) || 32;
						var x = bbox.x + (bbox.width - width) / 2 + (Number(iconConfig.offsetX) || 0);
						var y = bbox.y + (bbox.height - height) / 2 + (Number(iconConfig.offsetY) || 0);

						imageNode.setAttribute('width', String(width));
						imageNode.setAttribute('height', String(height));

						imageNode.setAttribute('x', String(x));
						imageNode.setAttribute('y', String(y));
					} catch (error) {
						continue;
					}
				}
		}

		function paintActive(nextIndex) {
			index = (nextIndex + list.length) % list.length;

			for (var i = 0; i < list.length; i += 1) {
				var region = list[i];
				region.classList.remove('region-active');
				region.classList.add('region-muted');
			}

			var activeRegion = list[index];
			activeRegion.classList.remove('region-muted');
			activeRegion.classList.add('region-active');

			if (regionNode) {
				regionNode.textContent = 'Region: ' + getRegionName(index, activeRegion);
			}
		}

		function stopScan() {
			if (timer) {
				clearInterval(timer);
				timer = null;
			}

			if (statusNode) {
				statusNode.textContent = 'Mode scan: jeda';
			}
		}

		function startScan() {
			stopScan();
			if (statusNode) {
				statusNode.textContent = 'Mode scan: aktif';
			}

			timer = setInterval(function () {
				paintActive(index + 1);
			}, 1400);
		}

		for (var i = 0; i < list.length; i += 1) {
			(function (region, regionIndex) {
				var label = getRegionName(regionIndex, region);
				if (!region.getAttribute('data-region-name')) {
					region.setAttribute('data-region-name', label);
				}
				region.setAttribute('tabindex', '0');
				region.setAttribute('role', 'button');
				region.setAttribute('aria-label', label);

				var title = document.createElementNS('http://www.w3.org/2000/svg', 'title');
				title.textContent = label;
				region.appendChild(title);

				region.addEventListener('mouseenter', function () {
					pausedByUser = true;
					stopScan();
					paintActive(regionIndex);
				});

				region.addEventListener('click', function () {
					pausedByUser = true;
					stopScan();
					paintActive(regionIndex);
				});

				region.addEventListener('focus', function () {
					pausedByUser = true;
					stopScan();
					paintActive(regionIndex);
				});
			})(list[i], i);
		}

		if (typeof MutationObserver !== 'undefined') {
			var regionNameObserver = new MutationObserver(function () {
				renderRegionLabels();
			});

			for (var o = 0; o < list.length; o += 1) {
				regionNameObserver.observe(list[o], {
					attributes: true,
					attributeFilter: ['data-region-name'],
				});
			}
		}

		root.addEventListener('mouseleave', function () {
			if (!pausedByUser) {
				startScan();
			}
		});

		root.addEventListener('keydown', function (event) {
			if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
				pausedByUser = true;
				stopScan();
				paintActive(index + 1);
			}

			if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
				pausedByUser = true;
				stopScan();
				paintActive(index - 1);
			}

			if (event.key === ' ') {
				event.preventDefault();
				pausedByUser = !pausedByUser;
				if (pausedByUser) {
					stopScan();
				} else {
					startScan();
				}
			}
		});

		ensureLabelLayerOnTop();
		renderRegionLabels();
		renderLandmarkIcons();
		paintActive(0);
		startScan();
	}

	if (document.readyState === 'loading') {
		document.addEventListener('DOMContentLoaded', function () {
			initScan(0);
		});
	} else {
		initScan(0);
	}
})();
